const express = require('express');
const app = express();
const port = 3000;
const axios = require('axios');

app.use(express.json());

// LLM API endpoint
const llmApiUrl = 'https://api.llama.tech/v1/completions';

// Function to generate code from prompt
async function generateCode(prompt) {
    try {
        const response = await axios.post(llmApiUrl, {
            model: 'code-davinci-002',
            prompt,
            max_tokens: 2048,
            temperature: 0.7,
            top_p: 1,
            n: 1,
            stream: false
        });

        return response.data.choices[0].text;
    } catch (error) {
        console.error(error);
        return null;
    }
}

// API endpoint to generate code from user input
app.post('/generate-code', async (req, res) => {
    const prompt = req.body.prompt;

    if (!prompt) {
        res.status(400).send({ error: 'Prompt is required' });
        return;
    }

    try {
        const generatedCode = await generateCode(prompt);
        res.send(generatedCode);
    } catch (error) {
        console.error(error);
        res.status(500).send({ error: 'Failed to generate code' });
    }
});

// API endpoint to execute generated code
app.post('/execute-code', async (req, res) => {
    const code = req.body.code;

    if (!code) {
        res.status(400).send({ error: 'Code is required' });
        return;
    }

    try {
        // Execute the generated code here (e.g., using child_process or a library like jsdom)
        const result = await executeGeneratedCode(code);
        res.send(result);
    } catch (error) {
        console.error(error);
        res.status(500).send({ error: 'Failed to execute code' });
    }
});

